import type {Ref, MutableRefObject, RefCallback} from 'react';

type PossibleRef<T> = Ref<T> | undefined | null;

/**
 * Merges multiple React refs into a single ref callback.
 * Useful when a component needs both a local ref and a forwarded ref
 * pointing to the same DOM/native element.
 */
export function mergeRefs<T>(...refs: PossibleRef<T>[]): RefCallback<T> {
    return (instance: T | null) => {
        for (const ref of refs) {
            if (!ref) continue;
            if (typeof ref === 'function') {
                ref(instance);
            } else {
                (ref as MutableRefObject<T | null>).current = instance;
            }
        }
    };
}
